import base64
from pyotp import TOTP
import qrcode

def generate_totp_secret():
    return base64.b32encode(TOTP.random().provisioning_uri())

def create_qr_code(secret):
    uri = TOTP(base64.b32decode(secret)).provisioning_uri()
    qr = qrcode.QRCode(version=1, error_correction=qrcode.constants.ERROR_CORRECT_H, box_size=10, border=4)
    qr.add_data(uri)
    qr.make()
    img = qr.make_image()
    img.save('qr.png')  # save the QR code as an image

def validate_totp_code(secret, code):
    return TOTP(base64.b32decode(secret)).verify(code)